Rule.Source:
import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningPlan.Operation;
  import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.tools.Util;
  import java.util.List;
  import java.util.Iterator;
  import java.util.Map;
  import sailpoint.object.Identity;
  import sailpoint.api.IdentityService; 
  import sailpoint.object.Application;
  import sailpoint.tools.Util;
  import sailpoint.object.Link;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  private static Log gsuiteLog = LogFactory.getLog("sailpoint.ascension.rules.gsuite.beforeprov");
  log.info("GSuite: Before Prov Rule");
  String thisAppName = application.getName();
  log.info("GSUITE APP NAME: "+thisAppName);
  
  AccountRequest trimBlankAttributeRequests(AccountRequest accReq){
    List attrReqList = accReq.getAttributeRequests();
    if(attrReqList != null && attrReqList.size()>0){
      Iterator itr = attrReqList.iterator();
      while(itr.hasNext()){
        AttributeRequest attr = (AttributeRequest)itr.next();
        if(attr.getValue() == null || attr.getValue().equals("")){
          itr.remove();
        }
      }
      return accReq;
    }
    return accReq;
  }
  
  if (plan != null ) {
    log.info("GSuite: Before Prov Rule-1: Plan is not null: "+plan.toXml());
System.out.println("GSUITE PLAN Bin Before Rule: "+plan.toXml());
    Identity refIdentity = plan.getIdentity();
	boolean isInactive = refIdentity.isInactive();
    String identityName = refIdentity.getName();
    log.info("GSuite: Before Prov Rule-2: "+identityName);
    String samAccountName = refIdentity.getAttribute("samAccountName");
    log.info("GSuite: Before Prov Rule-3: "+samAccountName);
    String primaryEmail = getAttributeValueFromPlan(plan,thisAppName,"primaryEmail");
    String mainEmail = refIdentity.getAttribute("email");
    Map linkAttributeMap = getLinkAttributes(refIdentity,samAccountName);
    String determineNTAccountName(){return linkAttributeMap.get("displayName");}
    String determineTargetADApp() {return linkAttributeMap.get("applicationName");}
    String determineTargetDN() {return linkAttributeMap.get("accountDN");}
    boolean checkTargetConflict(){return linkAttributeMap.get("targetConflict");}
    log.info("GSuite: Before Prov Rule-3: "+samAccountName);
    log.info("GSuite: Before Prov Rule-4: "+linkAttributeMap.toString());
    boolean isPEAmitaHealth = primaryEmail != null ? primaryEmail.toUpperCase().endsWith("AMITAHEALTH.ORG") : false;
    log.info("IS PRIMARY EMAIL AMITA? "+isPEAmitaHealth);
    boolean isMainEmailAmita = mainEmail != null ? mainEmail.toUpperCase().endsWith("AMITAHEALTH.ORG") : false;
	List appLink = getIdentityAppLinks(refIdentity, thisAppName);
    if(isInactive || !appLink.isEmpty() || appLink.size() > 0){
     plan = getEmptyPlan(plan);
    } 
    if(null != plan){
        if(isMainEmailAmita || isPEAmitaHealth || null == samAccountName || null == determineNTAccountName() || null == determineTargetADApp() || null == determineTargetDN()){
          log.info("GSuite: Before Prov Rule-5: "+isPEAmitaHealth +","+ samAccountName +","+ determineNTAccountName() +","+determineTargetADApp() +","+ determineTargetDN());
          Map auditMap = new HashMap();
          auditMap.put("string1","GSuite Before Provisioning Plan For: "+identityName);
          auditMap.put("string2","Checking Plan For NT Acocunt Name,Target AD Application, and Target DN");
          auditMap.put("string3","Target samAccountName: "+determineNTAccountName());
          auditMap.put("string4","NT Account Name: "+determineNTAccountName()+" | Target AD App: "+determineTargetADApp()+" | Target DN: "+determineTargetDN()+" One or more of the preceeding values are empty, nullifying the ProvisioningPlan and Provisioning will not happen");
          logAuditEvent("GSuite-BeforeProvisioning",identityName,determineTargetADApp(),determineNTAccountName(), auditMap);
          plan = getEmptyPlan(plan);
          log.info("GSuite: Before Prov Rule-6: "+plan.toXml());
      }else{
        log.info("GSuite: Before Prov Rule: VALIDATIONS PASSED");
        List acctReqs = plan.getAccountRequests();
        List updateAcctReqs = new ArrayList();
				if(acctReqs != null && acctReqs.size()>0){
         log.info("GSuite: Before Prov Rule: VALIDATIONS PASSED: 1");
        callGsuiteAPIForAttributeUpdates(plan);
        log.info("GSuite: Before Prov Rule: VALIDATIONS PASSED: 2");
        Iterator it = acctReqs.iterator();
        while(it.hasNext()){
          AccountRequest accReq = (AccountRequest) it.next();
          boolean alreadyAdded = false;
          accReq = trimBlankAttributeRequests(accReq);  
          if(!accReq.getOp().toString().equalsIgnoreCase("Create")){
            log.info("GSuite: Before Prov Rule: VALIDATIONS PASSED: create");

            //Replace exisiting ProvisioningPlan for ALIASES attribute requests with ADD instead of SET for sychronizing ALIASES to GSuite.
            AttributeRequest attr = accReq.getAttributeRequest("aliases");

            if(null != attr && void != attr){ 
              String aliasesOperation = attr.getOperation().toString();
              if(Util.isNotNullOrEmpty(aliasesOperation) && (aliasesOperation.equalsIgnoreCase("Set") || aliasesOperation.equalsIgnoreCase("Add"))){
                AccountRequest newAcctReq = new AccountRequest();
                newAcctReq.setApplication("GSuite");
                newAcctReq.setNativeIdentity(accReq.getNativeIdentity());
                newAcctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
                List attrReqList = accReq.getAttributeRequests();
                if(null != attrReqList && void != attrReqList && attrReqList.size() > 0){
                  Iterator itr = attrReqList.iterator();
                  while(itr.hasNext()){
                    AttributeRequest attr = (AttributeRequest)itr.next();
                    if(attr.getName().equalsIgnoreCase("aliases")){ 
                      IdentityService is = new IdentityService(context);
                      List appLinks = is.getLinks(plan.getIdentity(), context.getObjectByName(Application.class, ("GSuite")));
                      if (null != appLinks && appLinks.size() > 0){
                        for(Link link : appLinks){
                          boolean isList = false;
                          List aliasesList = new ArrayList();
                          if (link.getAttribute("aliases") instanceof List){
                            isList = true;
                            aliasesList = link.getAttribute("aliases");
                          }
                          if(isList){
                            if(null != aliasesList && aliasesList.size() > 0){
                              if (attr.getValue() instanceof List){
                                for (String aliasToBeProv : attr.getValue()){
                                  if (!aliasesList.contains(aliasToBeProv)){
                                    gsuiteLog.debug("Add 1: " + aliasToBeProv);
                                    newAcctReq.add(new AttributeRequest("aliases", ProvisioningPlan.Operation.Add, aliasToBeProv)); 
                                  }
                                }
                              } else if(attr.getValue() instanceof String){
                                if(!aliasesList.contains(attr.getValue())){
                                  gsuiteLog.debug("Add 2: " + attr.getValue());
                                  newAcctReq.add(new AttributeRequest("aliases", ProvisioningPlan.Operation.Add, attr.getValue())); 
                                }
                              }
                            }
                          } else {
                            if(attr.getValue() instanceof String){
                              if(null != link.getAttribute("aliases")){
                                if(!link.getAttribute("aliases").equalsIgnoreCase(attr.getValue())){
                                  gsuiteLog.debug("Add 3: " + attr.getValue());
                                  newAcctReq.add(new AttributeRequest("aliases", ProvisioningPlan.Operation.Add, attr.getValue())); 
                                }
                              } else{
                                gsuiteLog.debug("Add 4: " + attr.getValue());
                                newAcctReq.add(new AttributeRequest("aliases", ProvisioningPlan.Operation.Add, attr.getValue())); 
                              }
                            } else if(attr.getValue() instanceof List) {
                              for(String aliasToBeProvStr : attr.getValue()){
                                gsuiteLog.debug("Add 5: " + aliasToBeProvStr);
                                newAcctReq.add(new AttributeRequest("aliases", ProvisioningPlan.Operation.Add, aliasToBeProvStr)); 
                              }
                            }
                          }
                        }
                      }
                    } else {
                      gsuiteLog.debug("Add 7");
                      newAcctReq.add(attr);
                    }
                  }
                  alreadyAdded = true;
                  gsuiteLog.debug("Add 8");
                  updateAcctReqs.add(newAcctReq);  
                }
              }
            } 
          }
          if(!alreadyAdded){
            gsuiteLog.debug("Add 9");
            updateAcctReqs.add(accReq);
          }
        }
        plan.setAccountRequests(updateAcctReqs);
      }
  		}
    }
 }
  log.info("GSuite: Before Prov Rule: VALIDATIONS PASSED: create");
System.out.println("GSUITE PLAN Bin Before Rule: "+plan.toXml());
log.info("GSUITE PLAN Bin Before Rule: "+plan.toXml());
  gsuiteLog.trace("plan: " + plan.toXml());
